function Footer() {
    const navigate = useNavigate();
    function handleNavigate(path){
      console.log(path);
      navigate(path);
    }
    return (
      <nav className="footer">
        <p> Connect with Me! </p>
        <a href='https://www.linkedin.com/in/fabian-toh-98-smuis/'>
            <img src="../../img/linkedin.png"/>
        </a>
      </nav>
      );
    }
     
export default Footer;
